243: // GetNodeAllocatableAbsolute returns the absolute value of Node Allocatable which is primarily useful for enforcement.
244: // Note that not all resources that are available on the node are included in the returned list of resources.
245: // Returns a ResourceList.
246: func (cm *containerManagerImpl) GetNodeAllocatableAbsolute() v1.ResourceList {
247: 	cm.RLock()
248: 	defer cm.RUnlock()
249: 	return cm.getNodeAllocatableAbsoluteImpl(cm.capacity)
250: }
251: 
252: func (cm *containerManagerImpl) getNodeAllocatableAbsoluteImpl(capacity v1.ResourceList) v1.ResourceList {
253: 	result := make(v1.ResourceList)
254: 	for k, v := range capacity {
255: 		value := v.DeepCopy()
256: 		if cm.NodeConfig.SystemReserved != nil {
257: 			value.Sub(cm.NodeConfig.SystemReserved[k])
258: 		}
259: 		if cm.NodeConfig.KubeReserved != nil {
260: 			value.Sub(cm.NodeConfig.KubeReserved[k])
261: 		}
262: 		if value.Sign() < 0 {
263: 			// Negative Allocatable resources don't make sense.
264: 			value.Set(0)
265: 		}
266: 		result[k] = value
267: 	}
268: 	return result
269: }
