302: // validateNodeAllocatable ensures that the user specified Node Allocatable Configuration doesn't reserve more than the node capacity.
303: // Returns error if the configuration is invalid, nil otherwise.
304: func (cm *containerManagerImpl) validateNodeAllocatable() error {
305: 	cm.RLock()
306: 	defer cm.RUnlock()
307: 	var errors []string
308: 	nar := cm.GetNodeAllocatableReservation()
309: 	for k, v := range nar {
310: 		value := cm.capacity[k].DeepCopy()
311: 		value.Sub(v)
312: 
313: 		if value.Sign() < 0 {
314: 			errors = append(errors, fmt.Sprintf("Resource %q has a reservation of %v but capacity of %v. Expected capacity >= reservation.", k, v, cm.capacity[k]))
315: 		}
316: 	}
317: 
318: 	if len(errors) > 0 {
319: 		return fmt.Errorf("invalid Node Allocatable configuration. %s", strings.Join(errors, " "))
320: 	}
321: 	return nil
322: }
