120: // NewContainerManager creates windows container manager.
121: func NewContainerManager(ctx context.Context, mountUtil mount.Interface, cadvisorInterface cadvisor.Interface, nodeConfig NodeConfig, failSwapOn bool, recorder record.EventRecorder, kubeClient clientset.Interface) (ContainerManager, error) {
122: 	// It is safe to invoke `MachineInfo` on cAdvisor before logically initializing cAdvisor here because
123: 	// machine info is computed and cached once as part of cAdvisor object creation.
124: 	// But `RootFsInfo` and `ImagesFsInfo` are not available at this moment so they will be called later during manager starts
125: 	machineInfo, err := cadvisorInterface.MachineInfo()
126: 	if err != nil {
127: 		return nil, err
128: 	}
129: 	capacity := cadvisor.CapacityFromMachineInfo(machineInfo)
130: 
131: 	cm := &containerManagerImpl{
132: 		capacity:          capacity,
133: 		nodeConfig:        nodeConfig,
134: 		cadvisorInterface: cadvisorInterface,
135: 	}
136: 
137: 	logger := klog.FromContext(ctx)
138: 
139: 	cm.topologyManager = topologymanager.NewFakeManager()
140: 	cm.cpuManager = cpumanager.NewFakeManager(logger)
141: 	cm.memoryManager = memorymanager.NewFakeManager(logger)
142: 
143: 	if utilfeature.DefaultFeatureGate.Enabled(kubefeatures.WindowsCPUAndMemoryAffinity) {
144: 		logger.Info("Creating topology manager")
145: 		cm.topologyManager, err = topologymanager.NewManager(machineInfo.Topology,
146: 			nodeConfig.TopologyManagerPolicy,
147: 			nodeConfig.TopologyManagerScope,
148: 			nodeConfig.TopologyManagerPolicyOptions)
149: 		if err != nil {
150: 			logger.Error(err, "Failed to initialize topology manager")
151: 			return nil, err
152: 		}
153: 
154: 		logger.Info("Creating cpu manager")
155: 		cm.cpuManager, err = cpumanager.NewManager(
156: 			logger,
157: 			nodeConfig.CPUManagerPolicy,
158: 			nodeConfig.CPUManagerPolicyOptions,
159: 			nodeConfig.CPUManagerReconcilePeriod,
160: 			machineInfo,
161: 			nodeConfig.NodeAllocatableConfig.ReservedSystemCPUs,
162: 			cm.GetNodeAllocatableReservation(),
163: 			nodeConfig.KubeletRootDir,
164: 			cm.topologyManager,
165: 		)
166: 		if err != nil {
167: 			logger.Error(err, "Failed to initialize cpu manager")
168: 			return nil, err
169: 		}
170: 		cm.topologyManager.AddHintProvider(logger, cm.cpuManager)
171: 
172: 		logger.Info("Creating memory manager")
173: 		cm.memoryManager, err = memorymanager.NewManager(
174: 			logger,
175: 			nodeConfig.MemoryManagerPolicy,
176: 			machineInfo,
177: 			cm.GetNodeAllocatableReservation(),
178: 			nodeConfig.MemoryManagerReservedMemory,
179: 			nodeConfig.KubeletRootDir,
180: 			cm.topologyManager,
181: 		)
182: 		if err != nil {
183: 			logger.Error(err, "Failed to initialize memory manager")
184: 			return nil, err
185: 		}
186: 		cm.topologyManager.AddHintProvider(logger, cm.memoryManager)
187: 	}
188: 
189: 	logger.Info("Creating device plugin manager")
190: 	cm.deviceManager, err = devicemanager.NewManagerImpl(nil, cm.topologyManager)
191: 	if err != nil {
192: 		return nil, err
193: 	}
194: 	cm.topologyManager.AddHintProvider(logger, cm.deviceManager)
195: 
196: 	return cm, nil
197: }
